Use ASP.NET Core's **`WebApplicationFactory<TEntryPoint>`** from the `Microsoft.AspNetCore.Mvc.Testing` package. It hosts your app in-memory — no real port, no real server — and gives you an `HttpClient` wired directly to the pipeline.

**1. Add the NuGet package to your test project:**

```
dotnet add package Microsoft.AspNetCore.Mvc.Testing
```

**2. Write a test class:**

```csharp
using System.Net.Http.Json;
using Microsoft.AspNetCore.Mvc.Testing;
using Xunit;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.Equal(1, body.GetProperty("id").GetInt32());
        Assert.True(body.GetProperty("result").TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsCall_ExecutesTool()
    {
        // Initialize first (stateful session may require it)
        await InitializeSession();

        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var content = body.GetProperty("result").GetProperty("content");
        Assert.False(content.EnumerateArray().First()
            .GetProperty("text").GetString() is null);
    }
}
```

**Key points:**

- **`Program`** must be accessible — add `public partial class Program { }` to the bottom of your `Program.cs` if it uses top-level statements.
- **No port binding** — `WebApplicationFactory` uses an in-process `TestServer`; requests never hit the network.
- **Session headers** — if your server uses `Mcp-Session-Id`, capture it from the `initialize` response and attach it to subsequent requests.
- **Customize config** — override `WebApplicationFactory.ConfigureWebHost` to swap services (e.g., mock databases) for test isolation.
- **SSE / Streamable HTTP** — for streaming responses, use `SendAsync` with `HttpCompletionOption.ResponseHeadersRead` and read the response stream line-by-line.
